     1|/**
     2| * IVX Reels — full-screen vertical video feed matching ivxholding.com exactly.
     3| *
     4| * Same backend the landing page uses:
     5| *   feed      → GET /api/ivx/video-platform/feed
     6| *   like      → POST /api/projects/:id/like
     7| *   save      → POST /api/projects/:id/save
     8| *   share     → POST /api/projects/:id/share
     9| *   follow    → POST /api/ivx/video-platform/follow
    10| *   report    → POST /api/ivx/video-platform/videos/:id/report
    11| *   comments  → GET/POST /api/projects/:id/comments
    12| */
    13|import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
    14|import {
    15|  View,
    16|  Text,
    17|  StyleSheet,
    18|  FlatList,
    19|  TouchableOpacity,
    20|  ActivityIndicator,
    21|  useWindowDimensions,
    22|  Platform,
    23|  Alert,
    24|  type ViewToken,
    25|} from 'react-native';
    26|import { Stack, useRouter, useLocalSearchParams } from 'expo-router';
    27|import { useSafeAreaInsets } from 'react-native-safe-area-context';
    28|import { Video, ResizeMode } from 'expo-av';
    29|import { LinearGradient } from 'expo-linear-gradient';
    30|import {
    31|  X,
    32|  Heart,
    33|  MessageCircle,
    34|  Share2,
    35|  Volume2,
    36|  VolumeX,
    37|  Play,
    38|  Bookmark,
    39|  Hexagon,
    40|  Users,
    41|  Home,
    42|} from 'lucide-react-native';
    43|import * as Haptics from 'expo-haptics';
    44|import { useQuery } from '@tanstack/react-query';
    45|
    46|import Colors from '@/constants/colors';
    47|import { fetchVideoFeed, fetchProjectReels, type FeedVideo } from '@/lib/video-feed';
    48|import {
    49|  toggleProjectLike,
    50|  trackProjectShare,
    51|  fetchProjectComments,
    52|  addProjectComment,
    53|  deleteProjectComment,
    54|  type ProjectComment,
    55|} from '@/lib/project-engagement';
    56|import {
    57|  toggleVideoSave,
    58|  toggleVideoFollow,
    59|  reportVideo,
    60|  trackVideoEvent,
    61|  getViewerId,
    62|  buildVideoShareUrl,
    63|} from '@/lib/video-platform';
    64|import ProjectCommentsSheet from '@/components/ProjectCommentsSheet';
    65|import ProjectShareSheet from '@/components/ProjectShareSheet';
    66|import { supabase } from '@/lib/supabase';
    67|
    68|const GOLD = Colors.primary;
    69|const LIKE_RED = Colors.error;
    70|
    71|interface EngagementState {
    72|  likeCount: number;
    73|  commentCount: number;
    74|  shareCount: number;
    75|  saveCount: number;
    76|  liked: boolean;
    77|  saved: boolean;
    78|  following: boolean;
    79|}
    80|
    81|function formatCount(n: number): string {
    82|  if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
    83|  if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
    84|  return String(n);
    85|}
    86|
    87|function compactCurrency(value: number): string {
    88|  if (value >= 1_000_000) {
    89|    const m = value / 1_000_000;
    90|    return `$${m % 1 === 0 ? m.toFixed(0) : m.toFixed(1)}M`;
    91|  }
    92|  if (value >= 1_000) {
    93|    const k = value / 1_000;
    94|    return `$${k % 1 === 0 ? k.toFixed(0) : k.toFixed(1)}K`;
    95|  }
    96|  return `$${Math.round(value)}`;
    97|}
    98|
    99|function parseVideoTitle(video: FeedVideo): { title: string; location: string | null; tourLabel: string } {
   100|  const raw = video.title ?? video.deal?.title ?? 'IVX Holdings';
   101|  const locationMatch = raw.match(/(.+?)\s*[—–]\s*([^,]+,\s*[A-Z]{2})/);
   102|  if (locationMatch) {
   103|    return { title: locationMatch[1].trim(), location: locationMatch[2].trim(), tourLabel: 'Property Tour' };
   104|  }
   105|  const tourMatch = raw.match(/(.+?)\s*[—–]\s*(.+)/);
   106|  if (tourMatch) {
   107|    const tour = tourMatch[2].trim();
   108|    const isLocation = /,\s*[A-Z]{2}/.test(tour);
   109|    return { title: tourMatch[1].trim(), location: isLocation ? tour : null, tourLabel: isLocation ? 'Property Tour' : tour };
   110|  }
   111|  return { title: raw, location: null, tourLabel: 'Property Tour' };
   112|}
   113|
   114|function useInvestmentOptions(dealType: string | null | undefined) {
   115|  const t = (dealType ?? '').toLowerCase();
   116|  const tokenized = { id: 'tokenized', label: 'Tokenized', icon: <Hexagon size={16} color={GOLD} />, tint: GOLD };
   117|  const jvDeals = { id: 'jvDeals', label: 'JV Deal', icon: <Users size={16} color={Colors.blue} />, tint: Colors.blue };
   118|  const buyers = { id: 'buyers', label: 'Buyer', icon: <Home size={16} color={Colors.green} />, tint: Colors.green };
   119|  switch (t) {
   120|    case 'jv':
   121|    case 'equity_split':
   122|    case 'hybrid':
   123|      return [tokenized, jvDeals, buyers];
   124|    case 'development':
   125|    case 'new_construction':
   126|    case 'rehab_construction':
   127|      return [jvDeals, tokenized, buyers];
   128|    case 'profit_sharing':
   129|      return [tokenized, buyers, jvDeals];
   130|    default:
   131|      return [tokenized, jvDeals, buyers];
   132|  }
   133|}
   134|
   135|type ReelChannel = 'all' | 'investment' | 'buyer' | 'seller';
   136|
   137|const CHANNELS: { id: ReelChannel; label: string }[] = [
   138|  { id: 'all', label: 'All' },
   139|  { id: 'investment', label: 'Investments' },
   140|  { id: 'buyer', label: 'Buyers' },
   141|  { id: 'seller', label: 'Sellers' },
   142|];
   143|
   144|interface FeedItemProps {
   145|  video: FeedVideo;
   146|  isActive: boolean;
   147|  height: number;
   148|  muted: boolean;
   149|  engagement: EngagementState;
   150|  onToggleMute: () => void;
   151|  onLike: (video: FeedVideo) => void;
   152|  onDoubleTapLike: (video: FeedVideo) => void;
   153|  onComment: (video: FeedVideo) => void;
   154|  onShare: (video: FeedVideo) => void;
   155|  onSave: (video: FeedVideo) => void;
   156|  onFollow: (video: FeedVideo) => void;
   157|  onReport: (video: FeedVideo) => void;
   158|  onViewDeal: (video: FeedVideo) => void;
   159|  onInvestNow: (video: FeedVideo) => void;
   160|}
   161|
   162|const FeedItem = React.memo(function FeedItem({
   163|  video,
   164|  isActive,
   165|  height,
   166|  muted,
   167|  engagement,
   168|  onToggleMute,
   169|  onLike,
   170|  onDoubleTapLike,
   171|  onComment,
   172|  onShare,
   173|  onSave,
   174|  onFollow,
   175|  onReport,
   176|  onViewDeal,
   177|  onInvestNow,
   178|}: FeedItemProps) {
   179|  const [paused, setPaused] = useState<boolean>(false);
   180|  const [showHeart, setShowHeart] = useState<boolean>(false);
   181|  const [progress, setProgress] = useState<number>(0);
   182|  const insets = useSafeAreaInsets();
   183|  const lastTapRef = useRef<number>(0);
   184|  const shouldPlay = isActive && !paused;
   185|
   186|  const deal = video.deal ?? null;
   187|  const investmentOptions = useInvestmentOptions(deal?.deal_type);
   188|
   189|  const handleTap = () => {
   190|    const now = Date.now();
   191|    if (now - lastTapRef.current < 320) {
   192|      lastTapRef.current = 0;
   193|      setShowHeart(true);
   194|      setTimeout(() => setShowHeart(false), 800);
   195|      onDoubleTapLike(video);
   196|    } else {
   197|      lastTapRef.current = now;
   198|      setTimeout(() => {
   199|        if (lastTapRef.current === now) {
   200|          setPaused(p => !p);
   201|        }
   202|      }, 330);
   203|    }
   204|  };
   205|
   206|  const parsed = parseVideoTitle(video);
   207|  const propertyTitle = deal?.title ?? parsed.title;
   208|  const isActiveStatus = (video.status ?? 'published') === 'published';
   209|
   210|  return (
   211|    <View style={[styles.item, { height }]}>
   212|      <TouchableOpacity
   213|        style={StyleSheet.absoluteFill}
   214|        activeOpacity={1}
   215|        onPress={handleTap}
   216|        onLongPress={() => onReport(video)}
   217|        testID={`video-item-${video.id}`}
   218|      >
   219|        <Video
   220|          source={{ uri: video.hls_url ?? video.video_url }}
   221|          style={StyleSheet.absoluteFill}
   222|          resizeMode={ResizeMode.COVER}
   223|          shouldPlay={shouldPlay}
   224|          isLooping
   225|          isMuted={muted}
   226|          onPlaybackStatusUpdate={(status) => {
   227|            if (status.isLoaded && status.durationMillis) {
   228|              setProgress(status.positionMillis / status.durationMillis);
   229|            }
   230|          }}
   231|          posterSource={
   232|            video.poster_url ?? video.thumbnail_url ?? video.preview_blur_url
   233|              ? { uri: (video.poster_url ?? video.thumbnail_url ?? video.preview_blur_url) as string }
   234|              : undefined
   235|          }
   236|          usePoster={!!(video.poster_url ?? video.thumbnail_url ?? video.preview_blur_url)}
   237|        />
   238|      </TouchableOpacity>
   239|
   240|      {/* Progress bar */}
   241|      <View style={styles.progressBar}>
   242|        <View style={[styles.progressFill, { width: `${progress * 100}%` }]} />
   243|      </View>
   244|
   245|      {!shouldPlay && (
   246|        <View pointerEvents="none" style={styles.centerPlay}>
   247|          <View style={styles.centerPlayCircle}>
   248|            <Play size={30} color="#000" fill="#000" />
   249|          </View>
   250|        </View>
   251|      )}
   252|
   253|      {showHeart && (
   254|        <View pointerEvents="none" style={styles.burstHeart}>
   255|          <Heart size={96} color={LIKE_RED} fill={LIKE_RED} />
   256|        </View>
   257|      )}
   258|
   259|      {/* Right action rail */}
   260|      <View style={[styles.rail, { bottom: insets.bottom + 96 }]}>
   261|        <TouchableOpacity
   262|          style={styles.railBtn}
   263|          onPress={() => onLike(video)}
   264|          testID={`video-like-${video.id}`}
   265|        >
   266|          <Heart
   267|            size={30}
   268|            color={engagement.liked ? LIKE_RED : '#fff'}
   269|            fill={engagement.liked ? LIKE_RED : 'transparent'}
   270|          />
   271|          <Text style={styles.railCount}>{formatCount(engagement.likeCount)}</Text>
   272|        </TouchableOpacity>
   273|
   274|        <TouchableOpacity
   275|          style={styles.railBtn}
   276|          onPress={() => onComment(video)}
   277|          testID={`video-comment-${video.id}`}
   278|        >
   279|          <MessageCircle size={30} color="#fff" />
   280|          <Text style={styles.railCount}>{formatCount(engagement.commentCount)}</Text>
   281|        </TouchableOpacity>
   282|
   283|        <TouchableOpacity
   284|          style={styles.railBtn}
   285|          onPress={() => onSave(video)}
   286|          testID={`video-save-${video.id}`}
   287|        >
   288|          <Bookmark
   289|            size={30}
   290|            color={engagement.saved ? GOLD : '#fff'}
   291|            fill={engagement.saved ? GOLD : 'transparent'}
   292|          />
   293|          <Text style={styles.railCount}>{formatCount(engagement.saveCount)}</Text>
   294|        </TouchableOpacity>
   295|
   296|        <TouchableOpacity
   297|          style={styles.railBtn}
   298|          onPress={() => onShare(video)}
   299|          testID={`video-share-${video.id}`}
   300|        >
   301|          <Share2 size={30} color="#fff" />
   302|          <Text style={styles.railCount}>{formatCount(engagement.shareCount)}</Text>
   303|        </TouchableOpacity>
   304|
   305|        <TouchableOpacity style={styles.railBtn} onPress={onToggleMute} testID={`video-mute-${video.id}`}>
   306|          {muted ? <VolumeX size={26} color="#fff" /> : <Volume2 size={26} color="#fff" />}
   307|        </TouchableOpacity>
   308|      </View>
   309|
   310|      {/* Bottom info + CTAs */}
   311|      <View pointerEvents="box-none" style={[styles.info, { bottom: insets.bottom + 32 }]}>
   312|        <LinearGradient
   313|          colors={['transparent', 'rgba(0,0,0,0.55)', 'rgba(0,0,0,0.82)']}
   314|          locations={[0, 0.35, 1]}
   315|          style={styles.bottomGradient}
   316|        />
   317|        <View style={styles.badgeRow}>
   318|          {deal ? <Text style={styles.badgeInvestment}>INVESTMENT</Text> : null}
   319|          {isActiveStatus ? <Text style={styles.badgeActive}>ACTIVE</Text> : null}
   320|        </View>
   321|        <Text style={styles.infoTitle} numberOfLines={1}>
   322|          {`${parsed.title} — ${parsed.tourLabel}`}
   323|        </Text>
   324|        <Text style={styles.infoPropertyTitle} numberOfLines={1}>
   325|          {propertyTitle}
   326|        </Text>
   327|        {parsed.location ? (
   328|          <Text style={styles.infoLocation} numberOfLines={1}>
   329|            {parsed.location}
   330|          </Text>
   331|        ) : null}
   332|        <View style={styles.metricRow}>
   333|          {deal?.expected_roi ? (
   334|            <View style={styles.metric}>
   335|              <Text style={styles.metricValue}>{deal.expected_roi}%</Text>
   336|              <Text style={styles.metricLabel}>ROI</Text>
   337|            </View>
   338|          ) : null}
   339|          {deal?.min_investment && deal.min_investment > 0 ? (
   340|            <View style={styles.metric}>
   341|              <Text style={styles.metricValue}>{compactCurrency(deal.min_investment)}</Text>
   342|              <Text style={styles.metricLabel}>MIN INVEST</Text>
   343|            </View>
   344|          ) : null}
   345|          {deal?.price && deal.price > 0 ? (
   346|            <View style={styles.metric}>
   347|              <Text style={styles.metricValue}>{((deal.min_investment ?? 0) / deal.price * 100).toFixed(4)}%</Text>
   348|              <Text style={styles.metricLabel}>MIN OWNERSHIP</Text>
   349|            </View>
   350|          ) : null}
   351|        </View>
   352|
   353|        <View style={styles.optionsRow}>
   354|          {investmentOptions.map((option) => (
   355|            <View key={option.id} style={styles.optionIcon}>
   356|              <View style={[styles.optionIconCircle, { borderColor: `${option.tint}66` }]}>
   357|                {option.icon}
   358|              </View>
   359|              <Text style={styles.optionIconLabel}>{option.label}</Text>
   360|            </View>
   361|          ))}
   362|        </View>
   363|
   364|        <View style={styles.ctaRowInner}>
   365|          {deal?.url || deal?.id ? (
   366|            <TouchableOpacity
   367|              style={styles.viewDealBtn}
   368|              onPress={() => onViewDeal(video)}
   369|              activeOpacity={0.85}
   370|              testID={`video-view-deal-${video.id}`}
   371|            >
   372|              <Text style={styles.viewDealText}>View Deal</Text>
   373|            </TouchableOpacity>
   374|          ) : null}
   375|          {deal?.id ? (
   376|            <TouchableOpacity
   377|              style={styles.investNowBtn}
   378|              onPress={() => onInvestNow(video)}
   379|              activeOpacity={0.85}
   380|              testID={`video-invest-${video.id}`}
   381|            >
   382|              <Text style={styles.investNowText}>Invest Now</Text>
   383|            </TouchableOpacity>
   384|          ) : null}
   385|        </View>
   386|      </View>
   387|    </View>
   388|  );
   389|});
   390|
   391|export default function VideosScreen() {
   392|  const router = useRouter();
   393|  const insets = useSafeAreaInsets();
   394|  const { height: windowHeight } = useWindowDimensions();
   395|  const params = useLocalSearchParams<{ type?: string }>();
   396|  const [activeIndex, setActiveIndex] = useState<number>(0);
   397|  const [muted, setMuted] = useState<boolean>(true);
   398|  const [userId, setUserId] = useState<string | null>(null);
   399|  const [viewerId, setViewerId] = useState<string | null>(null);
   400|  const [engagements, setEngagements] = useState<Record<string, EngagementState>>({});
   401|  const [toast, setToast] = useState<string | null>(null);
   402|  const [channel, setChannel] = useState<ReelChannel>('all');
   403|
   404|  const [commentsVideo, setCommentsVideo] = useState<FeedVideo | null>(null);
   405|  const [comments, setComments] = useState<ProjectComment[]>([]);
   406|  const [commentsTotal, setCommentsTotal] = useState<number>(0);
   407|  const [commentsLoading, setCommentsLoading] = useState<boolean>(false);
   408|  const [shareVideo, setShareVideo] = useState<FeedVideo | null>(null);
   409|
   410|  const feedQuery = useQuery({
   411|    queryKey: ['ivx-video-feed'],
   412|    queryFn: () => fetchVideoFeed(24),
   413|    staleTime: 60_000,
   414|  });
   415|
   416|  const allVideos: FeedVideo[] = useMemo(() => feedQuery.data ?? [], [feedQuery.data]);
   417|
   418|  const filteredVideos = useMemo(() => {
   419|    if (channel === 'all') return allVideos;
   420|    if (channel === 'investment') return allVideos.filter(v => v.deal && v.video_type !== 'reel');
   421|    if (channel === 'buyer') {
   422|      return allVideos.filter(
   423|        v =>
   424|          (v.deal?.deal_type ?? '').toLowerCase().includes('buy') ||
   425|          v.title?.toLowerCase().includes('buy') ||
   426|          v.title?.toLowerCase().includes('buyer')
   427|      );
   428|    }
   429|    if (channel === 'seller') {
   430|      return allVideos.filter(
   431|        v =>
   432|          (v.deal?.deal_type ?? '').toLowerCase().includes('sell') ||
   433|          v.title?.toLowerCase().includes('sell') ||
   434|          v.title?.toLowerCase().includes('seller')
   435|      );
   436|    }
   437|    return allVideos;
   438|  }, [allVideos, channel]);
   439|
   440|  const counts = useMemo(() => {
   441|    const all = allVideos.length;
   442|    const investment = allVideos.filter(v => v.deal && v.video_type !== 'reel').length;
   443|    const buyer = allVideos.filter(
   444|      v =>
   445|        (v.deal?.deal_type ?? '').toLowerCase().includes('buy') ||
   446|        v.title?.toLowerCase().includes('buy') ||
   447|        v.title?.toLowerCase().includes('buyer')
   448|    ).length;
   449|    const seller = allVideos.filter(
   450|      v =>
   451|        (v.deal?.deal_type ?? '').toLowerCase().includes('sell') ||
   452|        v.title?.toLowerCase().includes('sell') ||
   453|        v.title?.toLowerCase().includes('seller')
   454|    ).length;
   455|    return { all, investment, buyer, seller };
   456|  }, [allVideos]);
   457|
   458|  useEffect(() => {
   459|    let cancelled = false;
   460|    void getViewerId().then((id) => {
   461|      if (!cancelled) setViewerId(id);
   462|    });
   463|    void supabase.auth.getSession().then(({ data }) => {
   464|      if (!cancelled && data.session?.user?.id) setUserId(data.session.user.id);
   465|    }).catch(() => {});
   466|    return () => { cancelled = true; };
   467|  }, []);
   468|
   469|  useEffect(() => {
   470|    if (allVideos.length === 0) return;
   471|    setEngagements(prev => {
   472|      const next = { ...prev };
   473|      for (const v of allVideos) {
   474|        if (!next[v.id]) {
   475|          next[v.id] = {
   476|            likeCount: v.like_count ?? 0,
   477|            commentCount: v.comment_count ?? 0,
   478|            shareCount: v.share_count ?? 0,
   479|            saveCount: v.save_count ?? 0,
   480|            liked: false,
   481|            saved: false,
   482|            following: false,
   483|          };
   484|        }
   485|      }
   486|      return next;
   487|    });
   488|  }, [allVideos]);
   489|
   490|  useEffect(() => {
   491|    const activeVideo = filteredVideos[activeIndex];
   492|    if (!activeVideo) return;
   493|    void trackVideoEvent('view', activeVideo.id);
   494|  }, [activeIndex, filteredVideos]);
   495|
   496|  const showToast = useCallback((message: string) => {
   497|    setToast(message);
   498|    setTimeout(() => setToast(null), 2500);
   499|  }, []);
   500|
   501|  const onViewableItemsChanged = useRef(({ viewableItems }: { viewableItems: ViewToken[] }) => {
   502|    const first = viewableItems.find(v => v.isViewable);
   503|    if (first && typeof first.index === 'number') setActiveIndex(first.index);
   504|  }).current;
   505|
   506|  const viewabilityConfig = useRef({ itemVisiblePercentThreshold: 60 }).current;
   507|
   508|  const handleLike = useCallback(async (video: FeedVideo) => {
   509|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
   510|    setEngagements(prev => {
   511|      const cur = prev[video.id] ?? { likeCount: video.like_count ?? 0, commentCount: video.comment_count ?? 0, shareCount: video.share_count ?? 0, saveCount: video.save_count ?? 0, liked: false, saved: false, following: false };
   512|      return {
   513|        ...prev,
   514|        [video.id]: { ...cur, liked: !cur.liked, likeCount: cur.likeCount + (cur.liked ? -1 : 1) },
   515|      };
   516|    });
   517|    try {
   518|      const result = await toggleProjectLike(video.id, userId);
   519|      setEngagements(prev => ({
   520|        ...prev,
   521|        [video.id]: { ...(prev[video.id] as EngagementState), liked: result.liked, likeCount: result.likeCount },
   522|      }));
   523|    } catch {}
   524|  }, [userId]);
   525|
   526|  const handleDoubleTapLike = useCallback((video: FeedVideo) => {
   527|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
   528|    void trackVideoEvent('double_tap_like', video.id);
   529|    const cur = engagements[video.id];
   530|    if (!cur || !cur.liked) {
   531|      void handleLike(video);
   532|    }
   533|  }, [engagements, handleLike]);
   534|
   535|  const handleComment = useCallback(async (video: FeedVideo) => {
   536|    void Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
   537|    setCommentsLoading(true);
   538|    setCommentsVideo(video);
   539|    try {
   540|      const { comments: cmts, total } = await fetchProjectComments(video.id, 20, 0);
   541|      setComments(cmts);
   542|      setCommentsTotal(total);
   543|    } catch {} finally {
   544|      setCommentsLoading(false);
   545|    }
   546|  }, []);
   547|
   548|  const handleAddComment = useCallback(async (projectId: string, body: string, parentId?: string) => {
