     1|/**
     2| * Non-fatal OTA update error handler.
     3| *
     4| * The app must NEVER crash or show a fatal screen solely because an OTA
     5| * update download failed. This module wraps expo-updates in a safe boundary:
     6| *
     7| * - catches all update-check and update-download errors
     8| * - records diagnostics locally (update ID, channel, runtimeVersion, timestamp)
     9| * - continues with the embedded or cached bundle
    10| * - surfaces an optional non-blocking "Update unavailable" notice
    11| *
    12| * Native-level update checking is DISABLED in app.config.ts (updates.enabled: false)
    13| * to prevent the fatal `java.io.IOException: Failed to download remote update`
    14| * crash that occurs when the update URL is unreachable. This module provides
    15| * optional JS-level update checking that is fully non-fatal.
    16| */
    17|
    18|import { Platform } from 'react-native';
    19|
    20|export interface UpdateDiagnostics {
    21|  hasUpdate: boolean;
    22|  isRollback: boolean;
    23|  updateId: string | null;
    24|  channel: string | null;
    25|  runtimeVersion: string | null;
    26|  manifestCreatedAt: string | null;
    27|  checkedAt: string;
    28|  error: string | null;
    29|}
    30|
    31|const DIAGNOSTICS_KEY = 'ivx_ota_diagnostics';
    32|
    33|/**
    34| * Read the last recorded update diagnostics from AsyncStorage.
    35| * Safe to call on any platform — returns null on web or if unavailable.
    36| */
    37|export async function getUpdateDiagnostics(): Promise<UpdateDiagnostics | null> {
    38|  if (Platform.OS === 'web') {
    39|    return null;
    40|  }
    41|  try {
    42|    const AsyncStorage = (await import('@react-native-async-storage/async-storage')).default;
    43|    const raw = await AsyncStorage.getItem(DIAGNOSTICS_KEY);
    44|    return raw ? (JSON.parse(raw) as UpdateDiagnostics) : null;
    45|  } catch {
    46|    return null;
    47|  }
    48|}
    49|
    50|/**
    51| * Persist update diagnostics locally for debugging.
    52| */
    53|async function saveDiagnostics(diagnostics: UpdateDiagnostics): Promise<void> {
    54|  if (Platform.OS === 'web') {
    55|    return;
    56|  }
    57|  try {
    58|    const AsyncStorage = (await import('@react-native-async-storage/async-storage')).default;
    59|    await AsyncStorage.setItem(DIAGNOSTICS_KEY, JSON.stringify(diagnostics));
    60|  } catch {
    61|    // Non-critical — don't let storage failure escalate
    62|  }
    63|}
    64|
    65|/**
    66| * Safely check for updates without crashing the app.
    67| *
    68| * This function NEVER throws. If expo-updates is unavailable, if the update
    69| * server is unreachable, or if the downloaded manifest is invalid, it
    70| * silently returns diagnostics with the error recorded.
    71| *
    72| * @returns UpdateDiagnostics — always returns a result, never throws
    73| */
    74|export async function safelyCheckForUpdates(): Promise<UpdateDiagnostics> {
    75|  const baseDiagnostics: UpdateDiagnostics = {
    76|    hasUpdate: false,
    77|    isRollback: false,
    78|    updateId: null,
    79|    channel: null,
    80|    runtimeVersion: null,
    81|    manifestCreatedAt: null,
    82|    checkedAt: new Date().toISOString(),
    83|    error: null,
    84|  };
    85|
    86|  if (Platform.OS === 'web') {
    87|    return baseDiagnostics;
    88|  }
    89|
    90|  try {
    91|    // Dynamic import — expo-updates may not be available in all build modes
    92|    const updates = await import('expo-updates');
    93|
    94|    // Only proceed if updates are available in this build
    95|    if (!updates.useUpdates) {
    96|      return { ...baseDiagnostics, error: 'expo-updates API not available' };
    97|    }
    98|
    99|    // Get current update info for diagnostics
   100|    const currentUpdate = updates.useUpdates?.()?.currentlyRunning;
   101|    const channel = currentUpdate?.channel ?? null;
   102|    const runtimeVersion = currentUpdate?.runtimeVersion ?? null;
   103|    const updateId = currentUpdate?.updateId ?? null;
   104|    const manifestCreatedAt = (currentUpdate?.manifest as Record<string, unknown> | undefined)?.createdAt as string | null ?? null;
   105|
   106|    const diagnostics: UpdateDiagnostics = {
   107|      ...baseDiagnostics,
   108|      channel,
   109|      runtimeVersion,
   110|      updateId,
   111|      manifestCreatedAt,
   112|    };
   113|
   114|    // Attempt to check for updates — wrapped in try/catch
   115|    try {
   116|      const result = await updates.checkForUpdateAsync();
   117|
   118|      if (result.isAvailable) {
   119|        diagnostics.hasUpdate = true;
   120|        // Attempt to download — also non-fatal
   121|        try {
   122|          await updates.fetchUpdateAsync();
   123|          // Reload to apply the update on next launch
   124|          // Use a delay to let the UI show a success notice
   125|          setTimeout(() => {
   126|            try {
